-- ============================================================
-- Migration 019 — Section 6 (Market Analysis) content
-- Bulk-loads M2-S6-C2 (Litigation Support) and M2-S6-C3 (Estate & Tax),
-- 10 scenarios each (20 total).
--
-- Difficulty distribution per category:
--   #1, #2  · introductory
--   #3, #4  · basic
--   #5, #6  · intermediate
--   #7, #8  · advanced
--   #9, #10 · expert
--
-- After this migration:
--   - M2-S6-C2 (Litigation Support) has 10 of 10 scenarios loaded.
--   - M2-S6-C3 (Estate & Tax) has 10 of 10 scenarios loaded.
--   - Section 6 is 3 of 6 categories complete.
--
-- No schema changes. The market_indicator_analysis field type and the
-- six M2-S6 categories were created in migration 017. M2-S6-C1 was
-- loaded in migration 018; this migration follows the same pattern.
-- Section-level defaults from migration 017:
--   classification_options = ['Improving','Stable','Declining','Market-Dependent']
--   min_rationale_chars    = 20
--   context_labels_by_category[M2-S6-C2] = 'Litigation Context'
--   context_labels_by_category[M2-S6-C3] = 'Estate & Tax Context'
-- These are repeated explicitly in each field_options_override for
-- self-describing scenario rows.
--
-- Tables array shape:
--   Every scenario stores its indicator data table inside a
--   one-element 'tables' array, even when the source artifact had a
--   single cols/rows pair. Two-data-set scenarios (broad market +
--   submarket — C2 #9, C3 #9, C3 #10) also use a single tables[0]
--   entry with a wider cols array, matching migration 018's
--   convention for C1 #9 and #10.
--
-- Idempotency: this migration runs once and is recorded in the
-- migration tracker by the migration runner.
-- ============================================================

BEGIN;

-- ============================================================
-- M2-S6-C2 — Litigation Support (10 scenarios)
-- ============================================================


-- ─────────────────────────────────────────────────────
-- Scenario 1: 2244 Brookstone Way, Spartanburg — Pandemic-Peak Retrospective Damage Claim (Brookstone Park)
-- Category M2-S6-C2 #1 · difficulty 'introductory'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 1,
  'introductory',
  '2244 Brookstone Way, Spartanburg — Pandemic-Peak Retrospective Damage Claim (Brookstone Park)',
  'You are appraising the property at 2244 Brookstone Way, Spartanburg, SC 29301 (3BR/2BA, 1,780 SF, built 2008, ranch · Brookstone Park). Personal property damage claim. Plaintiff alleges diminution in value from a contractor defect. You are establishing market conditions as of the damage date to support a retrospective value opinion. All analysis must be limited to data available as of March 15, 2022. Section 6 — Market Analysis — requires you to identify which market indicators and external factors are present in the data package, classify each present indicator as Improving, Stable, Declining, or Market-Dependent based on the indicator data and external context, and write a market-supported rationale citing specific data from the indicator table or external context. Indicators not evidenced in the data package must be left unchecked. Every classification must be grounded in specific evidence — this assignment evaluates evidence-based market analysis, not pattern recognition or reflexive checklist behavior.'
FROM scenario_categories WHERE code = 'M2-S6-C2';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "2244 Brookstone Way, Spartanburg, SC 29301", "subject_summary": "3BR/2BA, 1,780 SF, built 2008, ranch · Brookstone Park", "school": "Spartanburg County School District 7", "effective_date": "March 15, 2022 (retrospective)", "context_label": "Litigation Context", "context_text": "Personal property damage claim. Plaintiff alleges diminution in value from a contractor defect. You are establishing market conditions as of the damage date to support a retrospective value opinion. All analysis must be limited to data available as of March 15, 2022."}, "tables": [{"label": "", "cols": ["Indicator", "Prior Period (Sept 2021-Feb 2022)", "Current Period (Jan-Mar 2022)"], "rows": [["Closed Sales", "42", "51"], ["Active Listings", "6", "3"], ["Median Days on Market", "12", "8"], ["Median Sale Price", "$198,500", "$219,800"], ["List-to-Sale Price Ratio", "102.1%", "105.3%"], ["Absorption Rate", "1.4 months", "0.8 months"]]}], "external": "Pandemic-era migration demand combined with historically low mortgage rates (sub-4%) drove unprecedented demand into the Spartanburg market as of the effective date. Remote work relocation from Charlotte and Atlanta accelerated buyer activity through early 2022.", "factors": [{"id": "abs", "label": "Absorption rate trend"}, {"id": "dom", "label": "Days on market trend"}, {"id": "lts", "label": "List-to-sale price ratio trend"}, {"id": "msp", "label": "Median sale price trend"}, {"id": "inv", "label": "Active listing inventory level"}, {"id": "mig", "label": "Pandemic migration and low-rate demand driver"}, {"id": "post", "label": "Current (post-effective-date) market conditions"}, {"id": "sea", "label": "Seasonal demand pattern"}], "net_conclusion": "Extreme seller''s market as of March 15, 2022. All indicators align - near-zero supply, accelerating demand, prices rising sharply. A strong positive time adjustment is supported from this effective date.", "commentary": "The primary teaching point is the retrospective hard wall. Many students reflexively cite current market conditions - in litigation support, the effective date is an absolute boundary. Anything that occurred after that date is inadmissible and constitutes improper hindsight that will be exposed on cross-examination.", "classification_options": ["Improving", "Stable", "Declining", "Market-Dependent"], "min_rationale_chars": 20}'::jsonb,
  '{"factors": {"abs": {"present": true, "classification": "Improving", "rationale": "Dropped from 1.4 to 0.8 months as of the effective date - extreme seller''s market conditions. This is the most important demand indicator and must be analyzed as of March 15, 2022 only."}, "dom": {"present": true, "classification": "Improving", "rationale": "Fell from 12 to 8 days - demand accelerating as of the effective date. Contemporaneous data confirms the improving designation."}, "lts": {"present": true, "classification": "Improving", "rationale": "Rose from 102.1% to 105.3% - buyers bidding well over asking price as of March 2022. A strong, documented seller''s market signal."}, "msp": {"present": true, "classification": "Improving", "rationale": "+10.7% - peak appreciation period in the Spartanburg market. All sales in the data package closed on or before the effective date."}, "inv": {"present": true, "classification": "Improving", "rationale": "Fell from 6 to 3 actives - near-zero supply as of the effective date. Constrained supply with surging demand is the defining characteristic of this market period."}, "mig": {"present": true, "classification": "Improving", "rationale": "Documented, verifiable demand surge driven by remote work relocation and sub-4% rates - both present and operative as of March 15, 2022."}, "post": {"present": false, "rationale": "CRITICAL DISTRACTOR: Data after the effective date is inadmissible in retrospective analysis. Including post-effective-date conditions constitutes improper hindsight and is a USPAP compliance violation in litigation support assignments."}, "sea": {"present": false, "rationale": "No seasonal data was provided. This is a distractor."}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'market_indicator_analysis'
WHERE sc.code = 'M2-S6-C2'
  AND s.order_index = 1;

