-- Scenario 2: 916 Fernwood Drive, Union — Rate-Shock Contract Rescission (Fernwood Heights)
-- Category M2-S6-C2 #2 · difficulty 'introductory'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 2,
  'introductory',
  '916 Fernwood Drive, Union — Rate-Shock Contract Rescission (Fernwood Heights)',
  'You are appraising the property at 916 Fernwood Drive, Union, SC 29379 (3BR/2BA, 1,490 SF, built 2002, ranch · Fernwood Heights). Contract rescission claim. Buyer seeks to unwind a purchase contract signed at this date, alleging material misrepresentation. You are establishing market conditions as of the contract execution date. All analysis must be limited to data contemporaneous with October 1, 2023. Section 6 — Market Analysis — requires you to identify which market indicators and external factors are present in the data package, classify each present indicator as Improving, Stable, Declining, or Market-Dependent based on the indicator data and external context, and write a market-supported rationale citing specific data from the indicator table or external context. Indicators not evidenced in the data package must be left unchecked. Every classification must be grounded in specific evidence — this assignment evaluates evidence-based market analysis, not pattern recognition or reflexive checklist behavior.'
FROM scenario_categories WHERE code = 'M2-S6-C2';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "916 Fernwood Drive, Union, SC 29379", "subject_summary": "3BR/2BA, 1,490 SF, built 2002, ranch · Fernwood Heights", "school": "Union County Schools", "effective_date": "October 1, 2023 (retrospective)", "context_label": "Litigation Context", "context_text": "Contract rescission claim. Buyer seeks to unwind a purchase contract signed at this date, alleging material misrepresentation. You are establishing market conditions as of the contract execution date. All analysis must be limited to data contemporaneous with October 1, 2023."}, "tables": [{"label": "", "cols": ["Indicator", "Prior Period (Apr-Sept 2023)", "Current Period (Apr-Oct 2023)"], "rows": [["Closed Sales", "18", "12"], ["Active Listings", "14", "22"], ["Median Days on Market", "41", "67"], ["Median Sale Price", "$162,500", "$156,800"], ["List-to-Sale Price Ratio", "96.8%", "94.1%"], ["Absorption Rate", "5.6 months", "8.8 months"]]}], "external": "Mortgage rates reached approximately 7.8-8.0% in fall 2023, the highest level in over 20 years. This materially reduced buyer purchasing power and froze activity, particularly in rural secondary markets like Union County.", "factors": [{"id": "abs", "label": "Absorption rate trend"}, {"id": "dom", "label": "Days on market trend"}, {"id": "lts", "label": "List-to-sale price ratio trend"}, {"id": "msp", "label": "Median sale price trend"}, {"id": "inv", "label": "Active listing inventory level"}, {"id": "int", "label": "Interest rate and affordability shock"}, {"id": "post", "label": "Post-effective-date rate reduction data (2024)"}, {"id": "sea", "label": "Seasonal demand pattern"}], "net_conclusion": "Buyer''s market, declining conditions as of October 1, 2023. All six present indicators align. A negative time adjustment from this effective date is supported by the contemporaneous data.", "commentary": "Scenario 2 is the mirror of Scenario 1 - the effective date distractor flips direction. Students may know the market improved through 2024 as rates eased, but that data is after the wall. The lesson: a declining market on the effective date does not become less negative because conditions subsequently improved. Post-effective-date data is inadmissible in both directions.", "classification_options": ["Improving", "Stable", "Declining", "Market-Dependent"], "min_rationale_chars": 20}'::jsonb,
  '{"factors": {"abs": {"present": true, "classification": "Declining", "rationale": "Rose from 5.6 to 8.8 months as of October 1, 2023 - well into buyer''s market territory. This is contemporaneous data reflecting conditions on and before the effective date."}, "dom": {"present": true, "classification": "Declining", "rationale": "Rose from 41 to 67 days - a dramatic slowdown in demand velocity as of the effective date."}, "lts": {"present": true, "classification": "Declining", "rationale": "Fell from 96.8% to 94.1% - buyers negotiating significant concessions below asking price as of October 2023."}, "msp": {"present": true, "classification": "Declining", "rationale": "Actual price decline of -3.5% confirmed in contemporaneous data. Price decline is a strong declining market signal."}, "inv": {"present": true, "classification": "Declining", "rationale": "Rose from 14 to 22 actives - supply building rapidly as demand dried up. Contemporaneous data."}, "int": {"present": true, "classification": "Declining", "rationale": "7.8-8.0% rates - a documented 20-year high as of this date - created a material buyer pool reduction, particularly in rural secondary markets like Union County."}, "post": {"present": false, "rationale": "CRITICAL DISTRACTOR: Federal Reserve rate cuts in late 2023 and 2024 are after the hard wall. The subsequent market improvement does not change conditions as of October 1, 2023. A declining market on the effective date does not become less negative because conditions later improved."}, "sea": {"present": false, "rationale": "No seasonal data was provided. This is a distractor."}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'market_indicator_analysis'
WHERE sc.code = 'M2-S6-C2'
  AND s.order_index = 2;

