-- Scenario 3: 2817 Reidville Road, Moore — Divorce Property Division at Market Inflection (Reidville Commons)
-- Category M2-S6-C2 #3 · difficulty 'basic'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 3,
  'basic',
  '2817 Reidville Road, Moore — Divorce Property Division at Market Inflection (Reidville Commons)',
  'You are appraising the property at 2817 Reidville Road, Moore, SC 29369 (4BR/2.5BA, 2,240 SF, built 2016, two-story · Reidville Commons). Divorce property division. The parties dispute market conditions as of the date of separation. Plaintiff''s appraiser argues the market was strongly improving. Defense appraiser argues conditions had already begun to soften. You must analyze only contemporaneous data and resolve the dispute. Section 6 — Market Analysis — requires you to identify which market indicators and external factors are present in the data package, classify each present indicator as Improving, Stable, Declining, or Market-Dependent based on the indicator data and external context, and write a market-supported rationale citing specific data from the indicator table or external context. Indicators not evidenced in the data package must be left unchecked. Every classification must be grounded in specific evidence — this assignment evaluates evidence-based market analysis, not pattern recognition or reflexive checklist behavior.'
FROM scenario_categories WHERE code = 'M2-S6-C2';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "2817 Reidville Road, Moore, SC 29369", "subject_summary": "4BR/2.5BA, 2,240 SF, built 2016, two-story · Reidville Commons", "school": "Spartanburg County School District 6", "effective_date": "June 30, 2022 (retrospective)", "context_label": "Litigation Context", "context_text": "Divorce property division. The parties dispute market conditions as of the date of separation. Plaintiff''s appraiser argues the market was strongly improving. Defense appraiser argues conditions had already begun to soften. You must analyze only contemporaneous data and resolve the dispute."}, "tables": [{"label": "", "cols": ["Indicator", "Prior Period (Jul-Dec 2021)", "Current Period (Jan-Jun 2022)"], "rows": [["Closed Sales", "39", "44"], ["Active Listings", "5", "6"], ["Median Days on Market", "10", "13"], ["Median Sale Price", "$272,000", "$291,500"], ["List-to-Sale Price Ratio", "104.2%", "103.7%"], ["Absorption Rate", "1.1 months", "1.4 months"]]}], "external": "Mortgage rates rose sharply from approximately 3.1% in January 2022 to 5.8% by June 30, 2022. Despite this increase, demand indicators remained strong as of the effective date, as many buyers rushed to close before rates rose further.", "factors": [{"id": "abs", "label": "Absorption rate trend"}, {"id": "dom", "label": "Days on market trend"}, {"id": "lts", "label": "List-to-sale price ratio trend"}, {"id": "msp", "label": "Median sale price trend"}, {"id": "inv", "label": "Active listing inventory level"}, {"id": "rate", "label": "Mortgage rate increase (headwind)"}, {"id": "post", "label": "Post-effective-date slowdown (Jul-Dec 2022)"}, {"id": "sea", "label": "Seasonal demand pattern"}], "net_conclusion": "Still a seller''s market as of June 30, 2022, though very early softening signals are present. The rate headwind is real but had not yet depressed demand indicators as of this date. Net: Improving/Market-Dependent. The defense position relies on prospective softening that had not yet occurred.", "commentary": "Scenario 3 introduces resolving a dispute between two expert positions using only contemporaneous data. The defense argument is partially correct - rates were rising sharply - but the data available as of June 30, 2022 still showed a strong seller''s market. The subsequent slowdown visible in July-December 2022 data is exactly the kind of hindsight that is inadmissible and will be exposed on cross-examination.", "classification_options": ["Improving", "Stable", "Declining", "Market-Dependent"], "min_rationale_chars": 20}'::jsonb,
  '{"factors": {"abs": {"present": true, "classification": "Market-Dependent", "rationale": "Rose from 1.1 to 1.4 months - still an extremely strong seller''s market, but the first hint of directional movement. Market-Dependent reflects this very early signal that had not yet resolved into a sustained trend."}, "dom": {"present": true, "classification": "Market-Dependent", "rationale": "Rose from 10 to 13 days - marginal increase but still extremely fast. The directional movement is present but not yet significant enough to call Declining."}, "lts": {"present": true, "classification": "Stable", "rationale": "104.2 to 103.7% - essentially flat. Sellers still receiving well over asking price. No meaningful directional signal as of June 30, 2022."}, "msp": {"present": true, "classification": "Improving", "rationale": "+7.2% - prices still rising meaningfully as of the effective date. This is a lagging indicator but it remains genuinely improving as of this date."}, "inv": {"present": true, "classification": "Stable", "rationale": "5 to 6 actives - marginal increase, still extremely constrained supply. Not indicative of a meaningful inventory shift as of June 30, 2022."}, "rate": {"present": true, "classification": "Declining", "rationale": "A 280 bps rate increase from January to June 2022 is a documented, material affordability shock - but as of June 30, 2022 it had not yet moved demand indicators into negative territory. Appropriate to note as a risk factor."}, "post": {"present": false, "rationale": "CRITICAL DISTRACTOR: The marked demand slowdown occurred after this effective date. The defense expert is relying on hindsight. As of June 30, 2022, the data package shows a still-strong seller''s market. Post-effective-date deterioration is inadmissible."}, "sea": {"present": false, "rationale": "No seasonal data was provided. This is a distractor."}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'market_indicator_analysis'
WHERE sc.code = 'M2-S6-C2'
  AND s.order_index = 3;

