FROM scenario_categories WHERE code = 'M2-S6-C2';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "4401 Woodruff Road, Simpsonville, SC 29681", "subject_summary": "3BR/2BA, 1,960 SF, built 2013, vinyl ranch · Woodruff Crossing", "school": "Greenville County - Hillcrest HS zone", "effective_date": "September 1, 2022 (retrospective)", "context_label": "Litigation Context", "context_text": "Insurance bad faith claim. Homeowner disputes insurer''s valuation following storm damage. The insurer''s appraiser cites market data through December 2022 to argue conditions were already declining as of the damage date. You must evaluate the contemporaneous data as of September 1, 2022 only."}, "tables": [{"label": "", "cols": ["Indicator", "Prior Period (Mar-Aug 2022)", "Current Period (Mar-Sep 2022)"], "rows": [["Closed Sales", "51", "43"], ["Active Listings", "4", "11"], ["Median Days on Market", "8", "19"], ["Median Sale Price", "$298,500", "$307,200"], ["List-to-Sale Price Ratio", "105.1%", "101.4%"], ["Absorption Rate", "0.9 months", "2.2 months"]]}], "external": "Mortgage rates rose from approximately 5.8% in March 2022 to 6.4% by September 1, 2022. Demand began softening in the current period as affordability pressure accelerated. Prices remained above prior period levels as of the effective date.", "factors": [{"id": "abs", "label": "Absorption rate trend"}, {"id": "dom", "label": "Days on market trend"}, {"id": "lts", "label": "List-to-sale price ratio trend"}, {"id": "msp", "label": "Median sale price trend"}, {"id": "inv", "label": "Active listing inventory level"}, {"id": "rate", "label": "Mortgage rate environment"}, {"id": "q4", "label": "Q4 2022 market data (Oct-Dec 2022)"}, {"id": "sea", "label": "Seasonal demand pattern"}], "net_conclusion": "Transitioning market as of September 1, 2022 - moving rapidly from peak seller''s conditions toward balanced. Market-Dependent designation is appropriate. The insurer''s use of Q4 2022 data is improper hindsight. As of September 1, prices remained above prior period levels.", "commentary": "The insurer''s appraiser commits the classic retrospective error - using data from after the effective date to support a lower value conclusion. Students must identify this hindsight contamination and exclude the post-effective-date data. The honest conclusion is that the market was transitioning as of September 1, not yet fully declining - which still supports the homeowner''s position relative to the insurer''s methodology.", "classification_options": ["Improving", "Stable", "Declining", "Market-Dependent"], "min_rationale_chars": 20}'::jsonb,
  '{"factors": {"abs": {"present": true, "classification": "Market-Dependent", "rationale": "Rose from 0.9 to 2.2 months as of September 1 - still in seller''s territory but moving rapidly toward balanced. Market-Dependent accurately captures this transitional state."}, "dom": {"present": true, "classification": "Declining", "rationale": "More than doubled from 8 to 19 days - a meaningful demand softening signal present as of the effective date."}, "lts": {"present": true, "classification": "Declining", "rationale": "Fell from 105.1% to 101.4% - significant loss of over-ask premium. Buyers recovering leverage as of September 1, 2022."}, "msp": {"present": true, "classification": "Improving", "rationale": "+2.9% - prices still above the prior period as of this date, though momentum is slowing. A lagging indicator that remains positive as of September 1, 2022."}, "inv": {"present": true, "classification": "Declining", "rationale": "Rose rapidly from 4 to 11 - inventory nearly tripled, a leading indicator of demand softening present as of the effective date."}, "rate": {"present": true, "classification": "Declining", "rationale": "Rate increase from 5.8% to 6.4% during the data period is a documented, material external factor accelerating affordability pressure as of September 1, 2022."}, "q4": {"present": false, "rationale": "CRITICAL DISTRACTOR: The insurer''s appraiser uses post-September data to support a lower value conclusion. This constitutes improper hindsight. As of September 1, prices remained above prior period levels. Post-effective-date data is inadmissible regardless of which party it favors."}, "sea": {"present": false, "rationale": "No seasonal data was provided. This is a distractor."}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'market_indicator_analysis'
WHERE sc.code = 'M2-S6-C2'
