  '',
  '{"subject": {"address_summary": "831 Verdant Hills Drive, Duncan, SC 29334", "subject_summary": "4BR/3BA, 2,680 SF, built 2020, new construction · Verdant Hills", "school": "Spartanburg County School District 5", "effective_date": "January 15, 2022 (retrospective)", "context_label": "Litigation Context", "context_text": "Construction defect litigation. Homebuilder disputes the claimed diminution in value from alleged defects. Both experts have provided market condition analyses, but each cherry-picks indicators. You must identify which indicators are present, resolve the selective use of data, and form an independent conclusion."}, "tables": [{"label": "", "cols": ["Indicator", "Prior Period (Jul-Dec 2021)", "Current Period (Jul 2021-Jan 2022)"], "rows": [["Closed Sales", "34", "41"], ["Active Listings", "4", "3"], ["Median Days on Market", "9", "7"], ["Median Sale Price", "$341,000", "$368,500"], ["List-to-Sale Price Ratio", "103.4%", "106.1%"], ["Absorption Rate", "1.2 months", "0.9 months"], ["New Construction Deliveries (Spartanburg Co., same price range)", "47", "31"]]}], "external": "As of January 15, 2022, mortgage rates remained historically low at approximately 3.4%. Demand in the new construction segment was particularly acute as supply chain delays constrained builder delivery rates, reducing the pipeline of available new homes. Migration demand from larger metros remained active. Plaintiff''s expert cites closing volume, absorption, and list-to-sale ratio as improving. Defense expert cites only the declining new construction delivery rate and argues the new construction market was contracting.", "factors": [{"id": "abs", "label": "Absorption rate trend"}, {"id": "dom", "label": "Days on market trend"}, {"id": "lts", "label": "List-to-sale price ratio trend"}, {"id": "msp", "label": "Median sale price trend"}, {"id": "inv", "label": "Active listing inventory level"}, {"id": "ncdr", "label": "New construction delivery rate"}, {"id": "rate", "label": "Low mortgage rate environment"}, {"id": "post", "label": "Post-effective-date rate increases (Feb 2022+)"}, {"id": "sea", "label": "Seasonal demand pattern"}], "net_conclusion": "Strong seller''s market as of January 15, 2022. Plaintiff''s selective use of demand indicators is directionally correct. Defense''s use of new construction delivery data is misleading - the supply reduction actually supported price appreciation. Every indicator in the data package points the same direction.", "commentary": "Scenario 5 introduces cherry-picking - the litigation appraiser''s most common methodological vulnerability on cross-examination. Students must identify that the defense expert mischaracterizes declining new construction deliveries as evidence of a contracting market, when supply-chain-constrained delivery actually tightened supply further in a demand-heavy environment. Using all available data, the correct conclusion is unambiguous.", "classification_options": ["Improving", "Stable", "Declining", "Market-Dependent"], "min_rationale_chars": 20}'::jsonb,
  '{"factors": {"abs": {"present": true, "classification": "Improving", "rationale": "1.2 to 0.9 months as of January 15, 2022 - extreme seller''s conditions. Plaintiff''s expert is correct that this indicator is improving."}, "dom": {"present": true, "classification": "Improving", "rationale": "9 to 7 days - demand accelerating as of the effective date. Contemporaneous data."}, "lts": {"present": true, "classification": "Improving", "rationale": "103.4 to 106.1% - buyers bidding strongly over ask. Plaintiff''s expert is directionally correct on this indicator."}, "msp": {"present": true, "classification": "Improving", "rationale": "+8.1% - strong appreciation as of January 2022. Contemporaneous and correct."}, "inv": {"present": true, "classification": "Stable", "rationale": "4 to 3 actives - still near-zero supply, essentially stable at the floor. No meaningful directional change."}, "ncdr": {"present": true, "classification": "Market-Dependent", "rationale": "CORRECT BUT MISUSED BY DEFENSE: Deliveries fell from 47 to 31 - but the supply chain constraint that caused this actually REDUCED competing supply, supporting further price appreciation in existing homes. Defense expert mischaracterizes a supply reduction as a demand signal. Market-Dependent reflects the uncertainty of its net impact."}, "rate": {"present": true, "classification": "Improving", "rationale": "3.4% rates as of January 15, 2022 - a primary demand driver, documented and operative as of the effective date."}, "post": {"present": false, "rationale": "CRITICAL DISTRACTOR: Mortgage rates began rising in February 2022, after the effective date. Neither expert may introduce this data. As of January 15, 2022, rates were still near historic lows."}, "sea": {"present": false, "rationale": "No seasonal data was provided. This is a distractor."}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'market_indicator_analysis'
WHERE sc.code = 'M2-S6-C2'
  AND s.order_index = 5;

