  'advanced',
  '1818 Oak Forest Road, Greenville — Lender Liability Expert Methodology Dispute (Oak Forest)',
  'You are appraising the property at 1818 Oak Forest Road, Greenville, SC 29609 (3BR/2BA, 1,920 SF, built 2005, ranch · Oak Forest). Lender liability dispute. Expert A (borrower''s expert) classifies the market as Declining as of July 1, 2022, using 6-month data showing softening demand. Expert B (lender''s expert) classifies the market as Improving, using 12-month trailing data showing strong price appreciation. You must evaluate both methodologies and identify the more defensible analysis. Section 6 — Market Analysis — requires you to identify which market indicators and external factors are present in the data package, classify each present indicator as Improving, Stable, Declining, or Market-Dependent based on the indicator data and external context, and write a market-supported rationale citing specific data from the indicator table or external context. Indicators not evidenced in the data package must be left unchecked. Every classification must be grounded in specific evidence — this assignment evaluates evidence-based market analysis, not pattern recognition or reflexive checklist behavior.'
FROM scenario_categories WHERE code = 'M2-S6-C2';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "1818 Oak Forest Road, Greenville, SC 29609", "subject_summary": "3BR/2BA, 1,920 SF, built 2005, ranch · Oak Forest", "school": "Greenville County - Wade Hampton HS zone", "effective_date": "July 1, 2022 (retrospective)", "context_label": "Litigation Context", "context_text": "Lender liability dispute. Expert A (borrower''s expert) classifies the market as Declining as of July 1, 2022, using 6-month data showing softening demand. Expert B (lender''s expert) classifies the market as Improving, using 12-month trailing data showing strong price appreciation. You must evaluate both methodologies and identify the more defensible analysis."}, "tables": [{"label": "", "cols": ["Indicator", "Prior Period (Jan-Jun 2022)", "Current Period (Jan-Jul 2022)"], "rows": [["Closed Sales", "47", "38"], ["Active Listings", "5", "14"], ["Median Days on Market", "11", "24"], ["Median Sale Price", "$287,500", "$296,800"], ["List-to-Sale Price Ratio", "104.8%", "100.7%"], ["Absorption Rate", "1.3 months", "2.8 months"], ["12-Month Trailing Median Price", "$264,000", "$296,800"]]}], "external": "Mortgage rates rose sharply from approximately 3.2% in January 2022 to 5.9% by July 1, 2022. Demand indicators softened rapidly in the current period. The 12-month trailing price appreciation of +12.4% was driven by the earlier low-rate period. Expert A uses only 6-month data to argue Declining. Expert B uses the 12-month trailing figure to argue Improving.", "factors": [{"id": "abs", "label": "Absorption rate trend"}, {"id": "dom", "label": "Days on market trend"}, {"id": "lts", "label": "List-to-sale price ratio trend"}, {"id": "msp", "label": "Median sale price (current period)"}, {"id": "inv", "label": "Active listing inventory level"}, {"id": "trail", "label": "12-month trailing price appreciation"}, {"id": "rate", "label": "Mortgage rate shock"}, {"id": "post", "label": "Post-effective-date data"}, {"id": "sea", "label": "Seasonal demand pattern"}], "net_conclusion": "Transitioning market as of July 1, 2022 - not fully declining (prices still above prior period) but demand indicators clearly deteriorating rapidly. Expert A overstates the decline; Expert B improperly uses trailing data to obscure current conditions. Market-Dependent/transitioning is the most accurate characterization.", "commentary": "Scenario 7 requires evaluating competing expert methodologies, not just identifying market indicators. Expert B''s core flaw is using trailing 12-month appreciation to mask current-period demand deterioration - a common litigation strategy that misrepresents the data. Expert A correctly identifies softening demand but overstates the conclusion. The most defensible analysis uses all available contemporaneous indicators, weights leading indicators appropriately, and acknowledges lagging indicators as such.", "classification_options": ["Improving", "Stable", "Declining", "Market-Dependent"], "min_rationale_chars": 20}'::jsonb,
  '{"factors": {"abs": {"present": true, "classification": "Declining", "rationale": "Rose from 1.3 to 2.8 months as of July 1 - rapid shift from aggressive seller''s toward balanced. Current-period data confirms softening."}, "dom": {"present": true, "classification": "Declining", "rationale": "More than doubled from 11 to 24 days - demand velocity declining materially as of the effective date."}, "lts": {"present": true, "classification": "Declining", "rationale": "104.8 to 100.7% - substantial loss of over-ask premium as of July 2022. Buyers recovering meaningful leverage."}, "msp": {"present": true, "classification": "Improving", "rationale": "Still above prior period (+3.2%) as of July 1, 2022 - a lagging indicator. Prices reflect prior-period transactions. Neither expert should over-rely on this alone."}, "inv": {"present": true, "classification": "Declining", "rationale": "Rose dramatically from 5 to 14 - a near-tripling of inventory signals accelerating demand softening."}, "trail": {"present": true, "classification": "Market-Dependent", "rationale": "12-month trailing appreciation of +12.4% is real data but reflects prior-period demand strength. Expert B misuses this metric by allowing the prior strong period to obscure current softening. Market-Dependent captures the methodological uncertainty of this figure."}, "rate": {"present": true, "classification": "Declining", "rationale": "280 bps increase over 6 months is the documented proximate cause of demand deterioration as of July 1, 2022."}, "post": {"present": false, "rationale": "CRITICAL DISTRACTOR: Neither expert may use data after July 1, 2022. Post-effective-date data is inadmissible regardless of which party''s position it supports."}, "sea": {"present": false, "rationale": "No seasonal data was provided. This is a distractor."}}}'::jsonb
