  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "3318 Pelham Road, Greenville, SC 29615", "subject_summary": "3BR/2BA, 1,680 SF, built 2000, ranch · Pelham Estates", "school": "Greenville County - Pelham Road corridor", "effective_date": "May 15, 2021 - date of death", "context_label": "Estate & Tax Context", "context_text": "Federal estate tax filing. Decedent passed May 15, 2021. You are retained to support the estate''s reported date-of-death value. All analysis must be strictly limited to data available as of May 15, 2021. IRS reviewers are alert to any post-death data bleeding into the analysis."}, "tables": [{"label": "", "cols": ["Indicator", "Prior Period (May-Oct 2020)", "Current Period (Nov 2020-May 2021)"], "rows": [["Closed Sales", "19", "28"], ["Active Listings", "8", "3"], ["Median Days on Market", "24", "11"], ["Median Sale Price", "$221,500", "$247,800"], ["List-to-Sale Price Ratio", "99.4%", "103.2%"], ["Absorption Rate", "3.8 months", "1.4 months"]]}], "external": "Sub-3.0% mortgage rates and pandemic-era migration from Charlotte and Atlanta drove an unprecedented demand surge into the Greenville market through early 2021. Remote work adoption enabled buyers to leave higher-cost metros, and the Pelham Road corridor - with strong school district access and established infrastructure - was a primary beneficiary.", "factors": [{"id": "abs", "label": "Absorption rate trend"}, {"id": "dom", "label": "Days on market trend"}, {"id": "lts", "label": "List-to-sale price ratio trend"}, {"id": "msp", "label": "Median sale price trend"}, {"id": "inv", "label": "Active listing inventory level"}, {"id": "mig", "label": "Pandemic migration and low-rate demand driver"}, {"id": "post", "label": "Post-effective-date market data (2022 rate increases)"}, {"id": "sea", "label": "Seasonal demand pattern"}], "net_conclusion": "Extreme seller''s market as of May 15, 2021. All indicators align - near-zero supply, accelerating demand, prices rising sharply. A strong positive time adjustment is supported from this effective date.", "commentary": "Scenario 1 establishes the estate hard wall at an unambiguous point - the peak pandemic seller''s market. The post-effective-date distractor tests whether students keep their analysis within the May 2021 boundary. IRS reviewers are particularly alert to appraisers who introduce post-death market data, in either direction, to adjust the reported estate value.", "classification_options": ["Improving", "Stable", "Declining", "Market-Dependent"], "min_rationale_chars": 20}'::jsonb,
  '{"factors": {"abs": {"present": true, "classification": "Improving", "rationale": "Dropped from 3.8 to 1.4 months as of May 15, 2021 - extreme seller''s market conditions. This is the most important demand indicator and must be analyzed as of the estate effective date only."}, "dom": {"present": true, "classification": "Improving", "rationale": "Fell from 24 to 11 days - demand accelerating sharply as of the effective date. Contemporaneous closed sale data confirms the improving designation."}, "lts": {"present": true, "classification": "Improving", "rationale": "Rose from 99.4% to 103.2% - buyers bidding over asking price as of May 2021. A strong, documented seller''s market signal in the contemporaneous data."}, "msp": {"present": true, "classification": "Improving", "rationale": "+11.9% in the current period - peak appreciation as of the effective date. All sales in the data package closed on or before May 15, 2021."}, "inv": {"present": true, "classification": "Improving", "rationale": "Fell from 8 to 3 actives - near-zero supply as of the effective date. Constrained supply with surging demand is the defining characteristic of this market period."}, "mig": {"present": true, "classification": "Improving", "rationale": "Documented, verifiable demand surge driven by remote work relocation and sub-3.0% rates - both present and operative as of May 15, 2021. A required external factor citation."}, "post": {"present": false, "rationale": "CRITICAL DISTRACTOR: Mortgage rates did not begin rising materially until early 2022. Any reference to post-May-2021 market changes is inadmissible. IRS reviewers are particularly alert to appraisers who bleed in post-death data to support a lower estate value."}, "sea": {"present": false, "rationale": "No seasonal data was provided in this package. This is a distractor - do not cite unsupported factors."}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
