  '',
  '{"subject": {"address_summary": "1204 Fairforest Way, Spartanburg, SC 29303", "subject_summary": "3BR/2BA, 1,540 SF, built 2003, vinyl ranch · Fairforest Crossing", "school": "Spartanburg County School District 7", "effective_date": "November 30, 2022 - date of death", "context_label": "Estate & Tax Context", "context_text": "Federal estate tax filing. Decedent passed November 30, 2022. The estate''s reported value is under IRS review. You must support the date-of-death market condition analysis using only contemporaneous data. The IRS may argue that subsequent market improvement proves the reported value was understated."}, "tables": [{"label": "", "cols": ["Indicator", "Prior Period (Nov 2021-May 2022)", "Current Period (Jun-Nov 2022)"], "rows": [["Closed Sales", "44", "29"], ["Active Listings", "6", "17"], ["Median Days on Market", "12", "38"], ["Median Sale Price", "$198,500", "$191,800"], ["List-to-Sale Price Ratio", "103.8%", "97.4%"], ["Absorption Rate", "1.6 months", "4.9 months"]]}], "external": "Mortgage rates rose from approximately 3.5% in early 2022 to over 7.0% by November 2022 - the most rapid rate increase in 40 years. The prior 7-12 month period reflects the earlier strong market; the current period reflects the full demand impact of the rate shock.", "factors": [{"id": "abs", "label": "Absorption rate trend"}, {"id": "dom", "label": "Days on market trend"}, {"id": "lts", "label": "List-to-sale price ratio trend"}, {"id": "msp", "label": "Median sale price trend"}, {"id": "inv", "label": "Active listing inventory level"}, {"id": "rate", "label": "Mortgage rate shock"}, {"id": "post", "label": "Post-effective-date stabilization data (2023)"}, {"id": "sea", "label": "Seasonal demand pattern"}], "net_conclusion": "Clear buyer''s market, declining conditions as of November 30, 2022. All six present indicators align. A negative time adjustment from this effective date is supported by the contemporaneous data.", "commentary": "Scenario 2 mirrors Scenario 1 in direction - the effective date distractor flips. In an estate context, an IRS auditor might argue that subsequent market improvement proves the estate''s reported value was too low. The appraiser''s defense is identical: the effective date is the date of death, full stop. Post-death market improvement - in either direction - is irrelevant and inadmissible.", "classification_options": ["Improving", "Stable", "Declining", "Market-Dependent"], "min_rationale_chars": 20}'::jsonb,
  '{"factors": {"abs": {"present": true, "classification": "Declining", "rationale": "Rose from 1.6 to 4.9 months - crossed well past balanced into buyer''s market territory as of November 30, 2022. Contemporaneous data."}, "dom": {"present": true, "classification": "Declining", "rationale": "Tripled from 12 to 38 days - a severe demand slowdown fully reflected in data as of the effective date."}, "lts": {"present": true, "classification": "Declining", "rationale": "103.8 to 97.4% - lost all over-ask premium and dropped below asking price. A strong declining market signal in contemporaneous data."}, "msp": {"present": true, "classification": "Declining", "rationale": "Actual price decline of -3.4% confirmed in the data package. Price decline is the strongest declining market signal."}, "inv": {"present": true, "classification": "Declining", "rationale": "Nearly tripled from 6 to 17 actives - supply building rapidly as demand froze."}, "rate": {"present": true, "classification": "Declining", "rationale": "7.0%+ rates as of November 2022 - a documented 40-year high - created a material buyer pool reduction, particularly in this price range."}, "post": {"present": false, "rationale": "CRITICAL DISTRACTOR: Rates stabilized and the market improved through 2023, but this data is after the hard wall. An IRS argument that subsequent improvement proves the estate value was understated relies on inadmissible post-death data."}, "sea": {"present": false, "rationale": "No seasonal data was provided. This is a distractor."}}}'::jsonb
