INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "2241 Woodburn Road, Duncan, SC 29334", "subject_summary": "4BR/2BA, 2,040 SF, built 2011, two-story · Woodburn Estates", "school": "Spartanburg County School District 5", "effective_date": "August 1, 2021 - date of death", "context_label": "Estate & Tax Context", "context_text": "Estate appraisal for state inheritance tax purposes. The estate''s CPA requests a market condition analysis for supporting documentation that must withstand IRS document review. New construction activity in the market area introduces a classification challenge."}, "tables": [{"label": "", "cols": ["Indicator", "Prior Period (Aug 2020-Jan 2021)", "Current Period (Feb 2021-Aug 2021)"], "rows": [["Closed Sales", "28", "38"], ["Active Listings", "7", "4"], ["Median Days on Market", "22", "12"], ["Median Sale Price", "$228,500", "$249,800"], ["List-to-Sale Price Ratio", "101.2%", "104.8%"], ["Absorption Rate", "2.8 months", "1.4 months"], ["New Construction Deliveries (Spartanburg Co., same price range)", "58", "34"]]}], "external": "Lumber costs and supply chain disruptions reduced new construction deliveries significantly through mid-2021. Low mortgage rates averaging approximately 3.1% in the current period sustained strong buyer demand. Migration activity from larger metros continued.", "factors": [{"id": "abs", "label": "Absorption rate trend"}, {"id": "dom", "label": "Days on market trend"}, {"id": "lts", "label": "List-to-sale price ratio trend"}, {"id": "msp", "label": "Median sale price trend"}, {"id": "inv", "label": "Active listing inventory level"}, {"id": "rate", "label": "Low mortgage rate environment"}, {"id": "ncdr", "label": "New construction delivery decline"}, {"id": "post", "label": "Post-effective-date rate increases (early 2022)"}, {"id": "fut", "label": "Future rate increase announcements"}], "net_conclusion": "Strong seller''s market as of August 1, 2021. All demand indicators improving. New construction supply constraint is a real factor that - correctly analyzed - further supported price appreciation for existing homes. No post-effective-date data may be introduced.", "commentary": "Scenario 3 introduces the new construction delivery rate factor in the estate context. Students must correctly identify that declining deliveries reduced competing supply - a supportive, not negative, factor for existing home values. The IRS compliance note: the written market condition commentary must be thorough enough to withstand document review if the estate return is selected for examination.", "classification_options": ["Improving", "Stable", "Declining", "Market-Dependent"], "min_rationale_chars": 20}'::jsonb,
  '{"factors": {"abs": {"present": true, "classification": "Improving", "rationale": "2.8 to 1.4 months as of August 1, 2021 - strong seller''s market conditions confirmed in contemporaneous data."}, "dom": {"present": true, "classification": "Improving", "rationale": "22 to 12 days - accelerating demand velocity as of the effective date."}, "lts": {"present": true, "classification": "Improving", "rationale": "101.2 to 104.8% - strong over-ask bidding confirmed as of August 2021."}, "msp": {"present": true, "classification": "Improving", "rationale": "+9.3% - meaningful appreciation in the current period, fully reflected in closed sales before the effective date."}, "inv": {"present": true, "classification": "Improving", "rationale": "7 to 4 actives - constrained supply reinforcing the seller''s market picture as of August 1, 2021."}, "rate": {"present": true, "classification": "Improving", "rationale": "Sub-3.1% rates as of August 2021 - a primary, documented demand driver operative on the effective date."}, "ncdr": {"present": true, "classification": "Market-Dependent", "rationale": "Deliveries fell from 58 to 34 due to supply chain constraints. This reduction in competing supply actually supported further existing home price appreciation - but the net directional impact on market trajectory is uncertain. Market-Dependent is the appropriate classification."}, "post": {"present": false, "rationale": "CRITICAL DISTRACTOR: Rate increases did not materialize until early 2022, after the August 1, 2021 effective date. Inadmissible. The written analysis for the CPA must be confined to the effective date boundary."}, "fut": {"present": false, "rationale": "Forward guidance not operative and not reflected in contemporaneous market data as of August 1, 2021. This is a distractor."}}}'::jsonb
