-- Scenario 8: 2109 Haywood Road, Greenville — COVID-Trough Lagging vs. Leading Indicators (Haywood Hills)
-- Category M2-S6-C3 #8 · difficulty 'advanced'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 8,
  'advanced',
  '2109 Haywood Road, Greenville — COVID-Trough Lagging vs. Leading Indicators (Haywood Hills)',
  'You are appraising the property at 2109 Haywood Road, Greenville, SC 29607 (3BR/2BA, 1,840 SF, built 1988, ranch · Haywood Hills). Federal estate appraisal during the COVID disruption period. The market was still in disruption based on closed sale data, but leading indicators suggested a recovery was already underway as of July 31, 2020. You must characterize market conditions precisely as of this date using all available contemporaneous data including both lagging and leading indicators. Section 6 — Market Analysis — requires you to identify which market indicators and external factors are present in the data package, classify each present indicator as Improving, Stable, Declining, or Market-Dependent based on the indicator data and external context, and write a market-supported rationale citing specific data from the indicator table or external context. Indicators not evidenced in the data package must be left unchecked. Every classification must be grounded in specific evidence — this assignment evaluates evidence-based market analysis, not pattern recognition or reflexive checklist behavior.'
FROM scenario_categories WHERE code = 'M2-S6-C3';

INSERT INTO model_answers
