SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "2109 Haywood Road, Greenville, SC 29607", "subject_summary": "3BR/2BA, 1,840 SF, built 1988, ranch · Haywood Hills", "school": "Greenville County", "effective_date": "July 31, 2020 - date of death", "context_label": "Estate & Tax Context", "context_text": "Federal estate appraisal during the COVID disruption period. The market was still in disruption based on closed sale data, but leading indicators suggested a recovery was already underway as of July 31, 2020. You must characterize market conditions precisely as of this date using all available contemporaneous data including both lagging and leading indicators."}, "tables": [{"label": "", "cols": ["Indicator", "Prior Period (Aug 2019-Jan 2020, pre-COVID)", "Current Period (Feb-Jul 2020, COVID disruption)"], "rows": [["Closed Sales", "31", "19"], ["Active Listings", "7", "14"], ["Median Days on Market", "19", "41"], ["Median Sale Price", "$218,500", "$224,800"], ["List-to-Sale Price Ratio", "99.8%", "97.2%"], ["Absorption Rate", "2.8 months", "5.4 months"], ["Pending Sales (as of 7/31/20)", "-", "16"]]}], "external": "COVID-19 created a severe demand disruption beginning March 2020. By July 2020, mortgage rates had fallen to historic lows (sub-3.0%) and showings were recovering. Pending sales as of July 31 substantially exceeded the prior-month closed sale pace, indicating the market had already turned. Median sale prices held or marginally increased despite the disruption - a pattern observed across Upstate SC markets where distressed sales remained minimal.", "factors": [{"id": "abs", "label": "Absorption rate trend"}, {"id": "dom", "label": "Days on market trend"}, {"id": "lts", "label": "List-to-sale price ratio trend"}, {"id": "msp", "label": "Median sale price trend"}, {"id": "inv", "label": "Active listing inventory level"}, {"id": "pend", "label": "Pending sales count"}, {"id": "covid", "label": "COVID pandemic disruption"}, {"id": "rate", "label": "Historic low rate environment"}, {"id": "post", "label": "Post-effective-date recovery (Aug-Dec 2020)"}, {"id": "sea", "label": "Seasonal demand pattern"}], "net_conclusion": "Market-Dependent as of July 31, 2020. Closed sale data reflects the COVID demand shock (declining), but the pending count and rate environment provide strong leading indicators that the market was already past the trough and recovering. The appraiser must acknowledge the disruption while characterizing the leading indicators as evidence that conditions were Market-Dependent, not simply declining, as of this precise date.", "commentary": "Scenario 8 is the most technically demanding COVID-era scenario. Students must hold the tension between lagging indicators (closed sales showing decline) and leading indicators (pending count and falling rates showing recovery). The pending sales count - 16 contracts already under way as of July 31 - is the single most important data point for characterizing conditions on that precise date. The post-effective-date distractor is particularly seductive here because the August-December 2020 data strongly confirms the leading indicators.", "classification_options": ["Improving", "Stable", "Declining", "Market-Dependent"], "min_rationale_chars": 20}'::jsonb,
  '{"factors": {"abs": {"present": true, "classification": "Declining", "rationale": "2.8 to 5.4 months in the current period - closed sale data shows the COVID demand shock as of July 31, 2020. A lagging indicator but present and real."}, "dom": {"present": true, "classification": "Declining", "rationale": "19 to 41 days - homes sitting longer during the disruption period. Lagging indicator reflecting COVID hesitation."}, "lts": {"present": true, "classification": "Declining", "rationale": "99.8 to 97.2% - sellers accepting below-asking during COVID demand hesitation. Present in contemporaneous data."}, "msp": {"present": true, "classification": "Stable", "rationale": "Slight increase of +2.9% - prices did not decline despite the disruption. An important moderating signal that prevents a pure Declining designation."}, "inv": {"present": true, "classification": "Declining", "rationale": "7 to 14 actives - inventory built as demand hesitated during COVID. A lagging declining signal."}, "pend": {"present": true, "classification": "Market-Dependent", "rationale": "16 pending vs. 14 active as of July 31, 2020 - a strong leading recovery signal. Contracts being written at a pace that will close in August-September. The market was recovering as of the effective date even though closed data lags behind this reality. Market-Dependent captures the tension between lagging decline signals and this leading recovery indicator."}, "covid": {"present": true, "classification": "Declining", "rationale": "Documented proximate cause of demand disruption - must be identified and explained in the narrative. Operative as of July 31, 2020."}, "rate": {"present": true, "classification": "Market-Dependent", "rationale": "Sub-3.0% rates falling to near-record lows as of July 2020 - an emerging demand driver already pulling buyers back into the market. A forward-positive signal operative as of the effective date but not yet fully reflected in closed data."}, "post": {"present": false, "rationale": "CRITICAL DISTRACTOR: The strong recovery visible in closed sale data from August onward is after the hard wall of July 31, 2020. Highly seductive because it confirms what the leading indicators were already signaling - but inadmissible."}, "sea": {"present": false, "rationale": "No seasonal data was provided. This is a distractor."}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
